class NestedIterator {
public:
    NestedIterator(vector<NestedInteger> &nestedList) {
        flatten(nestedList);
    }

    int next() {
        int val = *it++;
        return val;
    }

    bool hasNext() {
        return it != nums.end();
    }

private:
    vector<int> nums;
    vector<int>::iterator it;

    void flatten(vector<NestedInteger> &nestedList) {
        for (const auto &ni : nestedList) {
            if (ni.isInteger()) {
                nums.push_back(ni.getInteger());
            } else {
                flatten(ni.getList());
            }
        }
        it = nums.begin();
    }
};
```
